-- calc_matchups_team1_score
-- Field: Matchups.Team1Score
-- Type: lookup | DataType: number | Returns: NUMERIC
-- Lookup: ProjectedScore from related Rosters


CREATE OR REPLACE FUNCTION calc_matchups_team1_score(p_matchup_id TEXT)
RETURNS NUMERIC AS $$
  SELECT calc_rosters_projected_score((SELECT team1 FROM matchups WHERE matchup_id = p_matchup_id));
$$ LANGUAGE sql STABLE;

-- calc_matchups_team2_score
-- Field: Matchups.Team2Score
-- Type: lookup | DataType: number | Returns: NUMERIC
-- Lookup: ProjectedScore from related Rosters


CREATE OR REPLACE FUNCTION calc_matchups_team2_score(p_matchup_id TEXT)
RETURNS NUMERIC AS $$
  SELECT calc_rosters_projected_score((SELECT team2 FROM matchups WHERE matchup_id = p_matchup_id));
$$ LANGUAGE sql STABLE;

-- calc_matchups_name
-- Field: Matchups.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_matchups_name(p_matchup_id TEXT)
RETURNS TEXT AS $$
  SELECT ((SELECT NULLIF(matchup_id, '') FROM matchups WHERE matchup_id = p_matchup_id))::text;
$$ LANGUAGE sql STABLE;

-- calc_matchups_margin
-- Field: Matchups.Margin
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_matchups_margin(p_matchup_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((COALESCE(CASE WHEN (calc_matchups_team1_score(p_matchup_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_matchups_team1_score(p_matchup_id))::numeric ELSE NULL END, 0) - COALESCE(CASE WHEN (calc_matchups_team2_score(p_matchup_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_matchups_team2_score(p_matchup_id))::numeric ELSE NULL END, 0)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_matchups_winner
-- Field: Matchups.Winner
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_matchups_winner(p_matchup_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN (calc_matchups_margin(p_matchup_id))::NUMERIC > 0 THEN ((SELECT NULLIF(team1, '') FROM matchups WHERE matchup_id = p_matchup_id))::text ELSE ((SELECT NULLIF(team2, '') FROM matchups WHERE matchup_id = p_matchup_id))::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_matchups_loser
-- Field: Matchups.Loser
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_matchups_loser(p_matchup_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN (calc_matchups_margin(p_matchup_id))::NUMERIC > 0 THEN ((SELECT NULLIF(team2, '') FROM matchups WHERE matchup_id = p_matchup_id))::text ELSE ((SELECT NULLIF(team1, '') FROM matchups WHERE matchup_id = p_matchup_id))::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_matchups_is_tie_game
-- Field: Matchups.IsTieGame
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_matchups_is_tie_game(p_matchup_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_matchups_margin(p_matchup_id))::NUMERIC = 0)::boolean;
$$ LANGUAGE sql STABLE;

